def seed():
    db = SessionLocal()
    try:
        count = db.query(models.Indicador).count()
        if count > 0:
            print(f"Ya existen {count} indicadores. Seed omitido.")
            return

        for row in INDICADORES:
            codigo, modulo, ud, cap, clase, modalidad, tipo, tipo_nombre, desc, cod_corto, clase_num = row
            ind = models.Indicador(
                codigo=codigo,
                modulo=modulo,
                unidad_didactica=ud,
                capacidad=cap,
                clase_titulo=clase,
                clase_numero=clase_num,
                modalidad=modalidad,
                tipo=tipo,
                tipo_nombre=tipo_nombre,
                descripcion=desc,
                codigo_corto=cod_corto
            )
            db.add(ind)

        db.commit()
        print(f"✅ {len(INDICADORES)} indicadores insertados correctamente.")
    except Exception as e:
        db.rollback()
        print(f"❌ Error: {e}")
    finally:
        db.close()


if __name__ == "__main__":
    seed()
